insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (1, 'Main Developer', 'Developer most responsible for the implementation, actual coding, of the project. The main developer typically contributes the most code and coordinates other developer contributions.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (3, 'Project Manager', 'Develops, maintains, and revises proposals for assigned projects including project objectives, technologies, systems, information specifications, timelines, funding, and staffing. Sets and tracks project milestones; manages and accounts for unforeseen delays, then realigns schedules and expectations as needed.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (4, 'Requestor', 'The customer or the person who is asking for the feature or capability. The project is being performed at the request of this person.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (2, 'Architect', 'A software architect is a computer programmer who makes project-specific software design choices, coordinates technical teams and selects and enforces technical coding standards when creating new programs or software to fulfill business goals.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (5, 'Functional Tester', 'A functional tester is someone who measures and monitors progress during each test to ensure that the application is tested, validated, and piloted on time and within budget, and that it meets or exceeds expectations. Review test, validation, and pilot results to ensure that they meet the entry and exit criteria.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (6, 'Contributing Developer', 'A developer who is not the main developer but is contributing to the development process for a specific project.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (7, 'Researcher', 'The Research Software Engineer works with researchers to gain an understanding of the problems they face, and then develops, maintains and extends software to provide the answers.', 'N');
insert into SP_RESOURCE_TYPES (ID, RESOURCE_TYPE, RESOURCE_DESCRIPTION, IS_DEFAULT_YN) values (8, 'UI Designer', 'A user interface designer, UI designer, is someone who designs the graphical user interface of an app, website, or device that a human interacts with. For example, when you access a website or an app on your phone, there''s usually a graphical interface that allows you to navigate and achieve your goal.', 'N');
